using System;
using System.Collections.Generic;
using ModProject.LiveStudio;

namespace ModProject
{
    public partial class Mod
    {
        // ── 聊天 "hello" 状态 ──────────────────────────────
        private HashSet<string> _seenChatMsgIds = new HashSet<string>();
        private Dictionary<string, DateTime> _lastHelloByUser = new Dictionary<string, DateTime>();

        // ── 礼物警车状态 ──────────────────────────────────
        private HashSet<string> _seenGiftMsgIds = new HashSet<string>();
        private DateTime _lastGiftCarSpawn = DateTime.MinValue;

        // ── 常数 ──────────────────────────────────────────
        private const int MaxSeenMsgIds = 500;
        private const int MaxCooldownEntries = 200;
        private static readonly TimeSpan HelloCooldown = TimeSpan.FromSeconds(5);
        private static readonly TimeSpan GiftCarCooldown = TimeSpan.FromSeconds(3);

        // ── 生命周期 ──────────────────────────────────────

        partial void InitializeGameplay()
        {
            _seenChatMsgIds = new HashSet<string>();
            _seenGiftMsgIds = new HashSet<string>();
            _lastHelloByUser = new Dictionary<string, DateTime>();
            _lastGiftCarSpawn = DateTime.MinValue;
        }

        partial void OnGameplayAborted()
        {
            _seenChatMsgIds.Clear();
            _seenGiftMsgIds.Clear();
            _lastHelloByUser.Clear();
        }

        // ── 聊天事件 ──────────────────────────────────────

        partial void OnChat(ChatEvent chat)
        {
            // 快速过滤：仅精确匹配 "hello"（大小写不敏感）
            if (string.IsNullOrEmpty(chat.Content)) return;
            if (!string.Equals(chat.Content.Trim(), "hello", StringComparison.OrdinalIgnoreCase)) return;

            EnqueueGameplay(() => HandleHelloChat(chat));
        }

        private void HandleHelloChat(ChatEvent chat)
        {
            // 去重
            if (_seenChatMsgIds.Contains(chat.MsgId)) return;

            // 按观众冷却
            if (_lastHelloByUser.TryGetValue(chat.UserId, out DateTime lastTime))
            {
                if ((DateTime.Now - lastTime) < HelloCooldown) return;
            }

            // 更新状态
            _seenChatMsgIds.Add(chat.MsgId);
            _lastHelloByUser[chat.UserId] = DateTime.Now;
            CleanupChatState();

            // 显示昵称通知
            try
            {
                GTA.UI.Notification.Show($"观众: {chat.Nickname}");
            }
            catch (Exception ex)
            {
                try
                {
                    GTA.UI.Screen.ShowSubtitle($"观众: {chat.Nickname}", 3000);
                }
                catch (Exception ex2)
                {
                    LogGameplay($"显示昵称失败: Notif={ex.Message}, Subtitle={ex2.Message}");
                }
            }
        }

        private void CleanupChatState()
        {
            if (_seenChatMsgIds.Count > MaxSeenMsgIds)
            {
                _seenChatMsgIds = new HashSet<string>();
            }
            if (_lastHelloByUser.Count > MaxCooldownEntries)
            {
                _lastHelloByUser = new Dictionary<string, DateTime>();
            }
        }

        // ── 礼物事件 ──────────────────────────────────────

        partial void OnGift(GiftEvent gift)
        {
            // 仅连击结束时触发（默认一次性策略）
            if (!gift.RepeatEnd) return;

            EnqueueGameplay(() => HandleGiftCar(gift));
        }

        private void HandleGiftCar(GiftEvent gift)
        {
            // 去重
            if (_seenGiftMsgIds.Contains(gift.MsgId)) return;

            // 全局冷却
            if ((DateTime.Now - _lastGiftCarSpawn) < GiftCarCooldown) return;

            // 更新状态
            _seenGiftMsgIds.Add(gift.MsgId);
            _lastGiftCarSpawn = DateTime.Now;
            CleanupGiftState();

            // 生成警车
            try
            {
                var player = GTA.Game.Player;
                if (player?.Character == null)
                {
                    LogGameplay("生成警车失败：无法获取玩家角色");
                    return;
                }

                var pos = player.Character.Position;
                var heading = player.Character.Heading;

                // 计算玩家前方 5 米偏移
                double rad = heading * Math.PI / 180.0;
                float fx = (float)Math.Sin(rad);
                float fy = (float)Math.Cos(rad);

                var spawnPos = new GTA.Math.Vector3(
                    pos.X + fx * 5f,
                    pos.Y + fy * 5f,
                    pos.Z
                );

                // 尝试生成警车（降级模型链）
                GTA.Vehicle vehicle = null;
                var modelHashes = new[]
                {
                    GTA.VehicleHash.Police,
                    GTA.VehicleHash.Police2,
                    GTA.VehicleHash.Police3
                };

                foreach (var vh in modelHashes)
                {
                    try
                    {
                        vehicle = GTA.World.CreateVehicle(new GTA.Model(vh), spawnPos, heading);
                        if (vehicle != null) break;
                    }
                    catch (Exception ex)
                    {
                        LogGameplay($"模型 {vh} 创建失败: {ex.Message}");
                    }
                }

                if (vehicle != null)
                {
                    // 成功提示
                    try
                    {
                        GTA.UI.Notification.Show($"{gift.Nickname} 的礼物召唤了一辆警车！");
                    }
                    catch (Exception ex)
                    {
                        try
                        {
                            GTA.UI.Screen.ShowSubtitle($"{gift.Nickname} 的礼物召唤了一辆警车！", 3000);
                        }
                        catch (Exception ex2)
                        {
                            LogGameplay($"警车提示失败: Notif={ex.Message}, Subtitle={ex2.Message}");
                        }
                    }
                }
                else
                {
                    LogGameplay("警车生成失败：所有模型均不可用");
                }
            }
            catch (Exception ex)
            {
                LogGameplay($"礼物警车生成异常: {ex.Message}");
            }
        }

        private void CleanupGiftState()
        {
            if (_seenGiftMsgIds.Count > MaxSeenMsgIds)
            {
                _seenGiftMsgIds = new HashSet<string>();
            }
        }
    }
}
